export interface IndustryItem {
  name: string
  slug: string
  description: string
  icon: string
  coverages: string[]
}

function toSlug(name: string): string {
  return name
    .toLowerCase()
    .replace(/[()]/g, '')
    .replace(/[&\/]/g, 'and')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
}

