export const allIndustries: IndustryItem[] = industryDefinitions.map(d => ({
  ...d,
  slug: toSlug(d.name),
}))

export function findIndustryBySlug(slug: string): IndustryItem | undefined {
  return allIndustries.find(i => i.slug === slug)
}
